namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private readonly Lock _lock = new();
    private readonly List<Notification> _notifications = [];
    private int _nextId = 1;

    public NotificationService()
    {
        // Seed with initial fake data.
        Add("Welcome to the notification center!");
        Add("Your profile was updated successfully.");
        Add("New team member Alice joined the project.");
    }

    /// <summary>Returns all notifications ordered newest-first.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications.OrderByDescending(n => n.Timestamp)];
        }
    }

    /// <summary>Returns only notifications newer than the given timestamp.</summary>
    public List<Notification> GetSince(DateTime since)
    {
        lock (_lock)
        {
            return [.. _notifications
                .Where(n => n.Timestamp > since)
                .OrderByDescending(n => n.Timestamp)];
        }
    }

    private void Add(string message)
    {
        _notifications.Add(new Notification(_nextId++, message, DateTime.UtcNow));
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called by a hosted service so the list grows while the app runs.
    /// </summary>
    public void GenerateRandom()
    {
        string[] samples =
        [
            "Deployment to production completed.",
            "Disk usage alert: 85% on server-02.",
            "Pull request #42 was merged.",
            "Scheduled maintenance window starts in 1 hour.",
            "New comment on issue #17.",
            "Build pipeline succeeded for main branch.",
            "Security scan found 0 vulnerabilities.",
            "User Bob requested access to the admin panel.",
        ];

        lock (_lock)
        {
            var msg = samples[Random.Shared.Next(samples.Length)];
            Add(msg);
        }
    }
}

namespace NotificationsApp.Services;

/// <summary>
/// Background service that periodically adds fake notifications
/// so the polling page has new data to discover.
/// </summary>
public class NotificationGeneratorService(NotificationService notifications) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            notifications.GenerateRandom();
        }
    }
}

