@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p class="text-muted">No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>
                    <strong>#@n.Id</strong> &mdash; @n.Message
                </div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = [];
    private CancellationTokenSource? _cts;

    // OnInitialized runs during SSR *and* again when the component
    // becomes interactive.  We load data here so the initial server
    // render already contains the full notification list in HTML.
    protected override void OnInitialized()
    {
        _notifications = NotificationSvc.GetAll();
    }

    // OnAfterRenderAsync with firstRender==true fires only once the
    // component is live on the circuit — never during static SSR.
    // This is the safe place to kick off the polling loop.
    protected override Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }

        return Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            // Fetch the latest snapshot; the service is the source of truth.
            var latest = NotificationSvc.GetAll();

            if (latest.Count != _notifications.Count)
            {
                _notifications = latest;
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

